tests.code:
config = {'db': {'host': 'localhost'}}
defaults = {'db': {'host': 'remote', 'port': 5432}, 'debug': False}
assert apply_defaults(config, defaults) == {'db': {'host': 'localhost', 'port': 5432}, 'debug': False}

config = {}
defaults = {'items': [], 'coords': (1, 2), 'nested': {'tags': ['a']}}
out = apply_defaults(config, defaults)
out['items'].append('new')
out['nested']['tags'].append('b')
assert defaults == {'items': [], 'coords': (1, 2), 'nested': {'tags': ['a']}}
assert out['coords'] == (1, 2)
assert isinstance(out['coords'], tuple)

config = {'a': {'b': 1}, 'keep': [1]}
defaults = {'a': {'c': 2}, 'keep': [9]}
original_config = {'a': {'b': 1}, 'keep': [1]}
original_defaults = {'a': {'c': 2}, 'keep': [9]}
out = apply_defaults(config, defaults)
assert out == {'a': {'b': 1, 'c': 2}, 'keep': [1]}
out['a']['b'] = 99
out['keep'].append(2)
assert config == original_config
assert defaults == original_defaults

config = {'section': 'disabled'}
defaults = {'section': {'enabled': True}}
assert apply_defaults(config, defaults) == {'section': 'disabled'}
